async function fetchUser(id: number): Promise<Result<any, ApplicationError>> {
  if (id <= 0) {
    return Err(new ValidationError("Invalid user ID", "id", id));
  }

  // Simulate API call that might fail
  const shouldFail = Math.random() > 0.7;

  if (shouldFail) {
    return Err(new NetworkError("Failed to fetch user", 500, `/api/users/${id}`));
  }

  // Simulate user not found
  if (id === 404) {
    return Err(new NotFoundError("User", id));
  }

  return Ok({
    id,
    name: `User ${id}`,
    email: `user${id}@example.com`,
    age: 25
  });
}

function safeParse<T>(
  value: string,
  parser: (str: string) => T
): Result<T, ValidationError> {
  try {
    return Ok(parser(value));
  } catch (error) {
    return Err(new ValidationError(
      `Parse error: ${error instanceof Error ? error.message : error}`,
      "value",
      value
    ));
  }
}

function assertIsObject(value: unknown): asserts value is object {
  if (!isObject(value)) {
    throw new ValidationError("Expected object", "value", value);
  }
}

function assert(condition: any, message?: string): asserts condition {
  if (!condition) {
    throw new Error(message || "Assertion failed");
  }
}

function mapError<T, E, F>(
  result: Result<T, E>,
  fn: (error: E) => F
): Result<T, F> {
  return isErr(result) ? Err(fn(result.error)) : result;
}

function isObject(value: unknown): value is object {
  return typeof value === "object" && value !== null && !Array.isArray(value);
}

function isInstanceOf<T extends new (...args: any[]) => any>(
