async get(key: K, factory: () => Promise<V>): Promise<V> {
    if (this.cache.has(key)) {
      try {
        return await this.cache.get(key)!;
      } catch (error) {
        // Remove failed promise from cache
        this.cache.delete(key);
        throw error;
      }
    }

    const promise = factory();
    this.cache.set(key, promise);

    // Set TTL
    setTimeout(() => {
      this.cache.delete(key);
    }, this.ttl);

    return promise;
  }

