  }

  // Concrete method
  public sleep(): string {
    return `${this.name} is sleeping.`;
  }

  // Abstract method (must be implemented by subclasses)
  abstract makeSound(): string;

  // Abstract method with parameters
  abstract move(distance: number): string;
}

